// Faktisk Studio · Bildeanalyse-plugin (MVP)
// Grid av 2-16 bilder (1-8 par) med rektangulære fargede rammer.
// Samme fargegruppe = samme entitet på tvers av bilder.
// Embed har klikkbar fargenøkkel som åpner lightbox filtrert per gruppe.

const PLUGIN_ID = 'bildeanalyse';

(async () => {
  try {
    const [appV, plugins] = await Promise.all([
      window.faktisk.appVersion(),
      window.faktisk.pluginStatus(),
    ]);
    const me = (plugins || []).find(p => p.id === PLUGIN_ID);
    const el = document.getElementById('appVersion');
    if (el && appV) {
      el.textContent = me ? 'v' + appV + ' · plugin v' + me.version : 'v' + appV;
    }
  } catch (e) {}
})();

const els = {
  imageList:     document.getElementById('imageList'),
  addImageBtn:   document.getElementById('addImageBtn'),
  loadBtn:       document.getElementById('loadBtn'),
  copyEmbed:     document.getElementById('copyEmbedBtn'),
  status:        document.getElementById('status'),
  back:          document.getElementById('backBtn'),
  full:          document.getElementById('fullscreenBtn'),
  captionText:   document.getElementById('captionText'),
  photographer:  document.getElementById('photographerText'),
  openLabrador:  document.getElementById('openLabradorBtn'),
  projectSelect: document.getElementById('projectSelect'),
  saveProject:   document.getElementById('saveProjectBtn'),
  stage:         document.getElementById('stage'),
  empty:         document.getElementById('emptyState'),
  grid:          document.getElementById('grid'),
  groupsSection: document.getElementById('groupsSection'),
  groupList:     document.getElementById('groupList'),
  videoSection:  document.getElementById('videoSection'),
  videoList:     document.getElementById('videoList'),
  addVideoBtn:   document.getElementById('addVideoBtn'),
  pairSection:   document.getElementById('pairSection'),
  pairTitle1:    document.getElementById('pairTitle1'),
  pairTitle2:    document.getElementById('pairTitle2'),
  pairFormatSelect: document.getElementById('pairFormatSelect'),
  captionLabel:  document.getElementById('captionLabel'),
  topHeading:    document.getElementById('topHeading'),
  headingStyle:  document.getElementById('headingStyle'),
  dimOutside:    document.getElementById('dimOutside'),
  abInCaption:   document.getElementById('abInCaption'),
};

const DEFAULT_GROUPS = [
  { id: 'g1', color: '#FFD500', label: 'Storskjerm' },
  { id: 'g2', color: '#00C853', label: 'Person 1' },
  { id: 'g3', color: '#0050FC', label: 'Person 2' },
  { id: 'g4', color: '#E91E63', label: 'Person 3' },
];

const state = {
  imageUrls: [''],
  imageLabels: [''],   // egen label per bilde (A, B, 1, 2 osv.)
  images: [],          // { url, aspectRatio, label }
  groups: DEFAULT_GROUPS.slice(),
  marks: [],
  selectedGroupId: 'g1',
  loaded: false,
  sourceVideos: [],
  showLabels: true,
  pairMode: 'auto',           // 'auto' = par-modus aktiv for ≥2 bilder
  pairFormat: '9:16',
  pairTitles: ['Bilde 1', 'Bilde 2'],
  activeSceneIdx: 0,
  sceneCaptions: [],
  topHeading: '',
  headingStyle: 'h2',   // 'h2' | 'small' | 'none'
  dimOutside: false,
  abInCaption: false,
};

function getSceneCaption(idx) {
  // Fallback til captionText hvis ingen scene-spesifikk caption finnes
  return (state.sceneCaptions && state.sceneCaptions[idx] !== undefined)
    ? state.sceneCaptions[idx]
    : (idx === 0 ? els.captionText.value : '');
}
function setSceneCaption(idx, txt) {
  if (!Array.isArray(state.sceneCaptions)) state.sceneCaptions = [];
  state.sceneCaptions[idx] = txt;
}

function isPair() {
  return state.pairMode === 'auto' && state.images.length >= 2;
}
function sceneCount() {
  // Hvert par av to bilder = én scene. Hvis odd antall, siste bilde danner egen "halv scene"
  return Math.ceil(state.images.length / 2);
}
function imagesForScene(idx) {
  const a = idx * 2;
  const b = a + 1;
  return {
    leftIdx: a,
    rightIdx: b < state.images.length ? b : null,
    left: state.images[a] || null,
    right: state.images[b] || null,
  };
}
function pairAspectRatio() {
  if (state.pairFormat === '9:16') return 9/16;
  if (state.pairFormat === '16:9') return 16/9;
  if (state.pairFormat === '1:1') return 1;
  return state.images[0] ? state.images[0].aspectRatio : 1;
}

function defaultLabel(idx) {
  // A, B, C ... Z
  return String.fromCharCode(65 + (idx % 26));
}

// Mux-URL: https://player.mux.com/ID...  ELLER  https://stream.mux.com/...
function isMuxUrl(url) {
  return /player\.mux\.com|stream\.mux\.com/i.test(url);
}
function muxIdFromUrl(url) {
  const m = url.match(/player\.mux\.com\/([^?\/#]+)/i) || url.match(/stream\.mux\.com\/([^.\/#]+)/i);
  return m ? m[1] : null;
}

function setStatus(msg, isError) {
  els.status.textContent = msg || '';
  els.status.style.color = isError ? '#FFB4B4' : '#fff';
}

function isValidUrl(s) {
  try {
    const u = new URL(s);
    return u.protocol === 'http:' || u.protocol === 'https:';
  } catch (e) { return false; }
}

function loadImageDim(url) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve({ url, aspectRatio: img.naturalWidth / img.naturalHeight });
    img.onerror = () => reject(new Error('Kunne ikke laste: ' + url));
    img.crossOrigin = 'anonymous';
    img.src = url;
  });
}

function escapeHtml(s) {
  return String(s).replace(/[<>&"]/g, c => ({
    '<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;'
  }[c]));
}

// ============================================================
//  Sidebar — URL-felt per bilde
// ============================================================
function renderImageInputs() {
  els.imageList.innerHTML = '';
  // Bygg DOM par-for-par. Hver par-container omslutter to rader og får en label
  // ("Par 1", "Par 2", …) så det visuelt er tydelig hva som hører sammen.
  // Hvis siste bilde er ufullstendig (odde antall) får det sin egen container
  // med dempet label "Ufullstendig par".
  const total = state.imageUrls.length;
  for (let p = 0; p < Math.ceil(total / 2); p++) {
    const a = p * 2;
    const b = a + 1;
    const isOddLast = (b >= total); // ingen partner — siste bilde er alene
    const pair = document.createElement('div');
    pair.className = 'image-pair' + (isOddLast ? ' image-pair--incomplete' : '');

    const header = document.createElement('div');
    header.className = 'image-pair__header';
    header.innerHTML = `<span class="image-pair__label">Par ${p + 1}${isOddLast ? ' (mangler ett bilde)' : ''}</span>`;
    pair.appendChild(header);

    for (let k = a; k <= b && k < total; k++) {
      const idx = k;
      const url = state.imageUrls[idx];
      const label = state.imageLabels[idx] !== undefined ? state.imageLabels[idx] : defaultLabel(idx);
      const row = document.createElement('div');
      row.className = 'image-list__row';
      row.innerHTML = `
        <input type="text" class="image-label-input" data-idx="${idx}" data-field="label" value="${escapeHtml(label)}" maxlength="3" title="Merkelapp (A, B, 1 …)" spellcheck="false">
        <input type="text" class="url-row__input" data-idx="${idx}" data-field="url" placeholder="https://faktisk.no/uploads/…" value="${escapeHtml(url)}" spellcheck="false" autocomplete="off">
        <button class="tb-row__btn tb-row__btn--del" data-act="removeImg" data-idx="${idx}" title="Fjern">×</button>
      `;
      pair.appendChild(row);
    }
    els.imageList.appendChild(pair);
  }
  els.imageList.oninput = e => {
    const idx = +e.target.dataset.idx;
    const field = e.target.dataset.field;
    if (field === 'url') {
      state.imageUrls[idx] = e.target.value;
      scheduleSaveState();
    } else if (field === 'label') {
      state.imageLabels[idx] = e.target.value;
      if (state.images[idx]) state.images[idx].label = e.target.value;
      renderGrid();
      scheduleSaveState();
    }
  };
  els.imageList.onclick = e => {
    if (e.target.dataset.act === 'removeImg') {
      const idx = +e.target.dataset.idx;
      state.imageUrls.splice(idx, 1);
      state.imageLabels.splice(idx, 1);
      if (state.imageUrls.length === 0) {
        state.imageUrls.push('');
        state.imageLabels.push(defaultLabel(0));
      }
      renderImageInputs();
      scheduleSaveState();
    }
  };
}

// Maks 16 bilder = 8 par. Vi bruker normalt 2-4 par per analyse, men en lang
// historie (f.eks. dokumentasjon av en hendelse over tid) kan trenge flere.
const MAX_IMAGES = 16;

function addImageInput() {
  if (state.imageUrls.length >= MAX_IMAGES) {
    setStatus('Maks ' + MAX_IMAGES + ' bilder (' + (MAX_IMAGES/2) + ' par).', true);
    return;
  }
  state.imageUrls.push('');
  state.imageLabels.push(defaultLabel(state.imageUrls.length - 1));
  renderImageInputs();
}

// ============================================================
//  Laste bildene
// ============================================================
async function loadAllImages() {
  const urls = state.imageUrls.map(u => u.trim()).filter(u => u);
  if (urls.length < 2) {
    setStatus('Legg til minst 2 bilder.', true);
    return;
  }
  const invalid = urls.find(u => !isValidUrl(u));
  if (invalid) {
    setStatus('Ugyldig URL: ' + invalid, true);
    return;
  }
  setStatus('Laster bilder…');
  try {
    const imgs = await Promise.all(urls.map(loadImageDim));
    // Sett label fra state.imageLabels (eller default A/B/C..)
    state.images = imgs.map((img, idx) => ({
      ...img,
      label: state.imageLabels[idx] || defaultLabel(idx),
    }));
    state.loaded = true;
    state.marks = state.marks.filter(m => m.imgIndex < imgs.length);
    els.empty.style.display = 'none';
    els.grid.style.display = 'block';
    els.groupsSection.style.display = 'flex';
    els.videoSection.style.display = 'flex';
    els.pairSection.style.display = isPair() ? 'flex' : 'none';
    syncCaptionFieldToScene();
    renderGrid();
    renderGroups();
    updateExportButtons();
    setStatus(`Lastet ${imgs.length} bilder`);
    scheduleSaveState();
  } catch (e) {
    setStatus(e.message, true);
    state.loaded = false;
    updateExportButtons();
  }
}

// ============================================================
//  Fargegrupper — sidebar-liste
// ============================================================
function renderGroups() {
  els.groupList.innerHTML = '';
  state.groups.forEach(g => {
    const row = document.createElement('div');
    row.className = 'tb-row';
    const isSelected = g.id === state.selectedGroupId;
    const count = new Set(state.marks.filter(m => m.groupId === g.id).map(m => m.imgIndex)).size;
    row.innerHTML = `
      <button class="group-chip ${isSelected ? 'group-chip--selected' : ''}" data-act="selectGroup" data-id="${g.id}" style="background:${g.color}" title="Klikk for å velge"></button>
      <input class="tb-row__input" value="${escapeHtml(g.label)}" data-id="${g.id}" data-act="editGroup" placeholder="Label">
      <input type="color" class="group-color-picker" value="${g.color}" data-id="${g.id}" data-act="editColor" title="Velg farge">
      <span class="group-count" title="Antall bilder med denne fargen">${count}</span>
    `;
    els.groupList.appendChild(row);
  });
  els.groupList.onclick = e => {
    const act = e.target.dataset.act;
    const id = e.target.dataset.id;
    if (act === 'selectGroup') {
      state.selectedGroupId = id;
      renderGroups();
    }
  };
  els.groupList.oninput = e => {
    const act = e.target.dataset.act;
    const id = e.target.dataset.id;
    const g = state.groups.find(gg => gg.id === id);
    if (!g) return;
    if (act === 'editGroup') {
      g.label = e.target.value;
      scheduleSaveState();
    } else if (act === 'editColor') {
      g.color = e.target.value;
      renderMarks();
      scheduleSaveState();
    }
  };
}

// ============================================================
//  Canvas — grid av bilder
// ============================================================
function renderGrid() {
  els.grid.innerHTML = '';
  if (isPair()) {
    renderPairLayout();
  } else {
    renderGridLayout();
  }
  renderMarks();
}

function renderGridLayout() {
  const n = state.images.length;
  const cols = n <= 1 ? 1 : (n <= 4 ? 2 : 3);
  els.grid.classList.remove('analysis-grid--pair');
  els.grid.classList.add('analysis-grid--cells');
  els.grid.style.display = 'grid';
  els.grid.style.gridTemplateColumns = `repeat(${cols}, 1fr)`;

  state.images.forEach((img, idx) => {
    const cell = document.createElement('div');
    cell.className = 'analysis-cell';
    cell.dataset.idx = idx;
    cell.style.aspectRatio = img.aspectRatio.toFixed(4);
    const labelChip = img.label ? `<span class="analysis-cell__label">${escapeHtml(img.label)}</span>` : '';
    cell.innerHTML = `<img src="${escapeHtml(img.url)}" alt="" draggable="false">${labelChip}`;
    cell.addEventListener('click', e => {
      if (e.target === cell || e.target.tagName === 'IMG' || e.target.classList.contains('analysis-cell__label')) {
        addMarkAtClick(idx, e, cell);
      }
    });
    els.grid.appendChild(cell);
  });
}

function renderPairLayout() {
  els.grid.classList.remove('analysis-grid--cells');
  els.grid.classList.add('analysis-grid--pair');
  els.grid.style.display = 'block';
  els.grid.style.gridTemplateColumns = '';

  // Pass på at aktiv scene er innenfor
  const total = sceneCount();
  if (state.activeSceneIdx >= total) state.activeSceneIdx = total - 1;
  if (state.activeSceneIdx < 0) state.activeSceneIdx = 0;

  const scene = imagesForScene(state.activeSceneIdx);
  const aspect = pairAspectRatio();

  // SVG chevroner (konsistent på iOS Safari — ikke emoji)
  const chevLeft = `<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/></svg>`;
  const chevRight = `<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" aria-hidden="true"><path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/></svg>`;
  // Piler + dots i samme rad OVER bildene
  const navHtml = total > 1 ? `
    <div class="pair-nav-row">
      <button class="pair-nav-btn" data-act="prevScene" aria-label="Forrige" ${state.activeSceneIdx === 0 ? 'disabled' : ''}>${chevLeft}</button>
      <div class="pair-dots">
        ${Array.from({length: total}, (_, i) => `<span class="pair-dot ${i === state.activeSceneIdx ? 'is-active' : ''}" data-act="goScene" data-idx="${i}"></span>`).join('')}
      </div>
      <button class="pair-nav-btn" data-act="nextScene" aria-label="Neste" ${state.activeSceneIdx === total - 1 ? 'disabled' : ''}>${chevRight}</button>
    </div>` : '';
  const dotsHtml = '';
  const arrowsHtml = '';
  const headingHtml = (() => {
    if (!state.topHeading || !state.topHeading.trim() || state.headingStyle === 'none') return '';
    const text = escapeHtml(state.topHeading);
    if (state.headingStyle === 'small') {
      return `<div class="pair-heading pair-heading--small">${text}</div>`;
    }
    return `<h2 class="pair-heading">${text}</h2>`;
  })();

  // Hvis bare ett bilde i scenen (odd antall totalt): vis bare ett
  const titleForSide = side => side === 'left'
    ? `<div class="pair-cell-title pair-cell-title--left">${escapeHtml(state.pairTitles[0] || 'Bilde 1')}</div>`
    : `<div class="pair-cell-title pair-cell-title--right">${escapeHtml(state.pairTitles[1] || 'Bilde 2')}</div>`;
  const cells = scene.right ? `
      ${[
        { idx: scene.leftIdx, img: scene.left, side: 'left' },
        { idx: scene.rightIdx, img: scene.right, side: 'right' },
      ].map(c => {
        return `
        <div class="pair-cell analysis-cell" data-idx="${c.idx}" data-side="${c.side}" style="aspect-ratio:${aspect.toFixed(4)};">
          <img src="${escapeHtml(c.img.url)}" alt="" draggable="false">
          ${titleForSide(c.side)}
        </div>`;
      }).join('')}
      <svg class="pair-connector" preserveAspectRatio="none"></svg>` : `
        <div class="pair-cell analysis-cell" data-idx="${scene.leftIdx}" data-side="left" style="aspect-ratio:${aspect.toFixed(4)};">
          <img src="${escapeHtml(scene.left.url)}" alt="" draggable="false">
          ${titleForSide('left')}
        </div>`;

  // Top-tekster legges INNE i hvert bilde (sort overlay) — venstre/høyre-justert
  const titleHtmlLeft = `<div class="pair-cell-title pair-cell-title--left">${escapeHtml(state.pairTitles[0] || 'Bilde 1')}</div>`;
  const titleHtmlRight = scene.right ? `<div class="pair-cell-title pair-cell-title--right">${escapeHtml(state.pairTitles[1] || 'Bilde 2')}</div>` : '';

  const wrapper = document.createElement('div');
  wrapper.className = 'pair-wrapper' + (state.dimOutside ? ' pair-wrapper--dimmed' : '');
  const cap = getSceneCaption(state.activeSceneIdx);
  let captionInner = '';
  if (cap && cap.trim()) {
    captionInner = escapeHtml(cap);
    if (state.abInCaption) {
      // Bytt [A] og [B] markører i teksten med faktiske chips
      captionInner = captionInner
        .replace(/\[A\]/g, '<span class="pair-ab-chip">A</span>')
        .replace(/\[B\]/g, '<span class="pair-ab-chip">B</span>');
    }
  }
  wrapper.innerHTML = `
    ${headingHtml}
    ${navHtml}
    <div class="pair-images${scene.right ? '' : ' pair-images--single'}">${cells}</div>
    ${captionInner ? `<div class="pair-caption">${captionInner}</div>` : ''}
  `;
  els.grid.appendChild(wrapper);

  wrapper.querySelectorAll('.pair-cell').forEach(cell => {
    const idx = +cell.dataset.idx;
    cell.addEventListener('click', e => {
      if (e.target === cell || e.target.tagName === 'IMG') {
        addMarkAtClick(idx, e, cell);
      }
    });
  });
  // Slideshow-navigasjon
  const goTo = (idx) => {
    state.activeSceneIdx = idx;
    syncCaptionFieldToScene();
    renderGrid();
  };
  wrapper.querySelectorAll('[data-act="prevScene"]').forEach(btn => btn.addEventListener('click', () => {
    if (state.activeSceneIdx > 0) goTo(state.activeSceneIdx - 1);
  }));
  wrapper.querySelectorAll('[data-act="nextScene"]').forEach(btn => btn.addEventListener('click', () => {
    if (state.activeSceneIdx < total - 1) goTo(state.activeSceneIdx + 1);
  }));
  wrapper.querySelectorAll('[data-act="goScene"]').forEach(dot => dot.addEventListener('click', () => {
    goTo(+dot.dataset.idx);
  }));
}

function addMarkAtClick(imgIndex, e, cell) {
  const rect = cell.getBoundingClientRect();
  const cx = (e.clientX - rect.left) / rect.width * 100;
  const cy = (e.clientY - rect.top) / rect.height * 100;
  const w = 25, h = 30;
  state.marks.push({
    id: 'm_' + Math.random().toString(36).slice(2, 7),
    imgIndex,
    x: Math.max(0, Math.min(100 - w, cx - w/2)),
    y: Math.max(0, Math.min(100 - h, cy - h/2)),
    w, h,
    groupId: state.selectedGroupId,
  });
  renderMarks();
  renderGroups();
  scheduleSaveState();
}

function renderMarks() {
  els.grid.querySelectorAll('.analysis-mark').forEach(n => n.remove());
  if (isPair()) drawPairConnectors();
  // I par-modus: vis kun markeringer for bilder som er i aktiv scene
  const visibleMarks = isPair()
    ? state.marks.filter(m => {
        const scene = imagesForScene(state.activeSceneIdx);
        return m.imgIndex === scene.leftIdx || (scene.rightIdx !== null && m.imgIndex === scene.rightIdx);
      })
    : state.marks;
  visibleMarks.forEach(m => {
    const cell = els.grid.querySelector(`.analysis-cell[data-idx="${m.imgIndex}"]`);
    if (!cell) return;
    const g = state.groups.find(g => g.id === m.groupId);
    const color = g ? g.color : '#fff';
    const mark = document.createElement('div');
    mark.className = 'analysis-mark';
    mark.style.left = m.x + '%';
    mark.style.top = m.y + '%';
    mark.style.width = m.w + '%';
    mark.style.height = m.h + '%';
    mark.style.setProperty('--mark-color', color);
    mark.dataset.id = m.id;
    // Label på markeringen — A for venstre, B for høyre (par-modus)
    let markLabel = '';
    if (isPair()) {
      const cellSide = cell.dataset.side;
      markLabel = cellSide === 'left' ? 'A' : 'B';
    }
    const labelHtml = markLabel ? `<div class="analysis-mark__label">${escapeHtml(markLabel)}</div>` : '';
    mark.innerHTML = `
      ${labelHtml}
      <div class="analysis-mark__scale"></div>
      <button class="analysis-mark__del" title="Slett">×</button>
    `;
    cell.appendChild(mark);
    attachMarkDrag(mark, m, 'move', cell);
    const handle = mark.querySelector('.analysis-mark__scale');
    if (handle) attachMarkDrag(handle, m, 'scale', cell);
    const del = mark.querySelector('.analysis-mark__del');
    if (del) del.addEventListener('click', ev => {
      ev.stopPropagation();
      state.marks = state.marks.filter(x => x.id !== m.id);
      renderMarks();
      renderGroups();
      scheduleSaveState();
    });
  });
}

function drawPairConnectors() {
  const svg = els.grid.querySelector('.pair-connector');
  if (!svg) return;
  const pairImages = els.grid.querySelector('.pair-images');
  if (!pairImages) return;
  const containerRect = pairImages.getBoundingClientRect();
  if (containerRect.width === 0) return;
  svg.setAttribute('viewBox', `0 0 ${containerRect.width} ${containerRect.height}`);
  svg.setAttribute('width', containerRect.width);
  svg.setAttribute('height', containerRect.height);
  svg.innerHTML = '';

  const scene = imagesForScene(state.activeSceneIdx);
  if (scene.rightIdx === null) return;  // bare ett bilde i denne scenen

  // Match markeringer per gruppe: én i venstre, én i høyre
  const groupMap = new Map();
  state.marks.forEach(m => {
    if (m.imgIndex !== scene.leftIdx && m.imgIndex !== scene.rightIdx) return;
    if (!groupMap.has(m.groupId)) groupMap.set(m.groupId, { left: null, right: null });
    if (m.imgIndex === scene.leftIdx) groupMap.get(m.groupId).left = m;
    else groupMap.get(m.groupId).right = m;
  });

  const cells = els.grid.querySelectorAll('.pair-cell');
  if (cells.length < 2) return;
  const c1 = cells[0].getBoundingClientRect();
  const c2 = cells[1].getBoundingClientRect();

  // Strek slutter på rammens kant + forlenges litt LANGS VEKTOREN så bratte
  // vinkler også treffer presist (uten dette ville en nesten-vertikal strek
  // ha en visuell glipe pga at stroke-tykkelsen står normalt på linjeretningen).
  const EXTEND = 3;
  groupMap.forEach((pair, gid) => {
    if (!pair.left || !pair.right) return;
    const g = state.groups.find(g => g.id === gid);
    const color = g ? g.color : '#fff';
    const a = pair.left, b = pair.right;
    let x1 = (c1.left + (a.x + a.w) * c1.width / 100) - containerRect.left;
    let y1 = (c1.top + (a.y + a.h/2) * c1.height / 100) - containerRect.top;
    let x2 = (c2.left + b.x * c2.width / 100) - containerRect.left;
    let y2 = (c2.top + (b.y + b.h/2) * c2.height / 100) - containerRect.top;
    // Forleng langs vektoren
    const dx = x2 - x1, dy = y2 - y1;
    const len = Math.sqrt(dx*dx + dy*dy);
    if (len > 0) {
      const ux = dx / len, uy = dy / len;
      x1 -= ux * EXTEND;
      y1 -= uy * EXTEND;
      x2 += ux * EXTEND;
      y2 += uy * EXTEND;
    }
    const line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    line.setAttribute('x1', x1);
    line.setAttribute('y1', y1);
    line.setAttribute('x2', x2);
    line.setAttribute('y2', y2);
    line.setAttribute('stroke', color);
    line.setAttribute('stroke-width', '4');
    line.setAttribute('stroke-linecap', 'butt');
    line.setAttribute('opacity', '1');
    svg.appendChild(line);
  });
}

function attachMarkDrag(el, m, kind, cell) {
  el.addEventListener('mousedown', e => {
    if (e.target.classList.contains('analysis-mark__del')) return;
    e.preventDefault();
    e.stopPropagation();
    const rect = cell.getBoundingClientRect();
    const startX = e.clientX, startY = e.clientY;
    const x0 = m.x, y0 = m.y, w0 = m.w, h0 = m.h;
    const move = ev => {
      const dxPct = (ev.clientX - startX) / rect.width * 100;
      const dyPct = (ev.clientY - startY) / rect.height * 100;
      if (kind === 'scale') {
        m.w = Math.max(5, Math.min(100 - m.x, w0 + dxPct));
        m.h = Math.max(5, Math.min(100 - m.y, h0 + dyPct));
      } else {
        m.x = Math.max(0, Math.min(100 - m.w, x0 + dxPct));
        m.y = Math.max(0, Math.min(100 - m.h, y0 + dyPct));
      }
      renderMarks();
    };
    const up = () => {
      document.removeEventListener('mousemove', move);
      document.removeEventListener('mouseup', up);
      scheduleSaveState();
    };
    document.addEventListener('mousemove', move);
    document.addEventListener('mouseup', up);
  });
}

