function renderVideoInputs() {
  els.videoList.innerHTML = '';
  state.sourceVideos.forEach((v, idx) => {
    const row = document.createElement('div');
    row.className = 'image-list__row';
    const kindHint = v.url ? (isMuxUrl(v.url) ? ' Mux' : ' Fil') : '';
    row.innerHTML = `
      <input type="text" class="url-row__input" data-idx="${idx}" data-field="url" placeholder="URL fra Labrador eller Mux…" value="${escapeHtml(v.url || '')}" spellcheck="false" autocomplete="off">
      <button class="tb-row__btn tb-row__btn--del" data-act="removeVideo" data-idx="${idx}" title="Fjern">×</button>
    `;
    els.videoList.appendChild(row);
  });
  els.videoList.oninput = e => {
    if (e.target.classList.contains('url-row__input')) {
      const idx = +e.target.dataset.idx;
      state.sourceVideos[idx].url = e.target.value;
      scheduleSaveState();
    }
  };
  els.videoList.onclick = e => {
    if (e.target.dataset.act === 'removeVideo') {
      const idx = +e.target.dataset.idx;
      state.sourceVideos.splice(idx, 1);
      renderVideoInputs();
      scheduleSaveState();
    }
  };
}

function addVideoInput() {
  if (state.sourceVideos.length >= 4) {
    setStatus('Maks 4 kilde-videoer', true);
    return;
  }
  state.sourceVideos.push({ url: '', label: '' });
  renderVideoInputs();
}

