function buildPairEmbed() {
  const id = 'banl-' + Math.random().toString(36).slice(2, 8);
  const aspect = pairAspectRatio();
  const captionText = (els.captionText.value || '').trim();
  const photographer = (els.photographer.value || '').trim();
  const title1 = state.pairTitles[0] || 'Bilde 1';
  const title2 = state.pairTitles[1] || 'Bilde 2';

  // Bygg scener: hver scene har left + right (eller bare left)
  const total = sceneCount();
  const scenes = [];
  for (let i = 0; i < total; i++) {
    const s = imagesForScene(i);
    scenes.push(s);
  }

  // For hver scene: beregn marks per bilde + connectors mellom dem
  const sceneData = scenes.map((s, sIdx) => {
    const leftMarks = state.marks.filter(m => m.imgIndex === s.leftIdx);
    const rightMarks = s.rightIdx !== null ? state.marks.filter(m => m.imgIndex === s.rightIdx) : [];
    // Connectors: match per groupId
    const groupMap = new Map();
    leftMarks.forEach(m => {
      if (!groupMap.has(m.groupId)) groupMap.set(m.groupId, { left: null, right: null });
      groupMap.get(m.groupId).left = m;
    });
    rightMarks.forEach(m => {
      if (!groupMap.has(m.groupId)) groupMap.set(m.groupId, { left: null, right: null });
      groupMap.get(m.groupId).right = m;
    });
    const connectors = [];
    groupMap.forEach((pair, gid) => {
      if (pair.left && pair.right) {
        const g = state.groups.find(g => g.id === gid);
        connectors.push({ a: pair.left, b: pair.right, color: g ? g.color : '#fff' });
      }
    });
    return { s, leftMarks, rightMarks, connectors };
  });

  // Marks-HTML helper — returnerer rektangelet UTEN label-sirkelen inni.
  // Rektanglene ligger inne i cell-clip og klippes mot bildemasken (riktig for spotlight-skygge).
  const marksHtml = (marks) => marks.map(m => {
    const g = state.groups.find(g => g.id === m.groupId);
    const c = g ? g.color : '#fff';
    return `
        <div class="banl-mark-${id}" style="left:${m.x.toFixed(2)}%;top:${m.y.toFixed(2)}%;width:${m.w.toFixed(2)}%;height:${m.h.toFixed(2)}%;--c:${c};"></div>`;
  }).join('');

  // Labels — ligger UTENFOR cell-clip, på cellen direkte, så de aldri klippes.
  // Posisjonert på markeringens top-left-hjørne (samme x%, y% som rektangelet).
  const labelsHtml = (marks, isLeft) => marks.map(m => {
    const lbl = isLeft ? 'A' : 'B';
    return `
        <span class="banl-mark-label-${id}" style="left:${m.x.toFixed(2)}%;top:${m.y.toFixed(2)}%;">${escapeHtml(lbl)}</span>`;
  }).join('');

  // Per scene: bygg connector-SVG med data-attr som JS bruker for pixel-beregning
  const buildConnectorSvg = (connectors) => connectors.length ? `
      <svg class="banl-conn-${id}" xmlns="http://www.w3.org/2000/svg">${connectors.map(c => {
        // Vi lagrer rå koordinater (i prosent av hver celle) som data-attr.
        // JS beregner pixel-koordinater på runtime (tar høyde for gap mellom bildene).
        return `
        <line data-ax="${(c.a.x + c.a.w).toFixed(2)}" data-ay="${(c.a.y + c.a.h/2).toFixed(2)}" data-bx="${c.b.x.toFixed(2)}" data-by="${(c.b.y + c.b.h/2).toFixed(2)}" stroke="${c.color}" stroke-linecap="butt"/>`;
      }).join('')}
      </svg>` : '';

  // captionText er fallback til scene 0 hvis ingen scene-spesifikk er satt

  // Wrappe i <figure> hvis vi har caption (Labrador-konvensjon)
  const hasFigureWrap = !!captionText;
  const figOpen = hasFigureWrap ? `<figure style="margin:0;">` : '';
  const figClose = hasFigureWrap ? `</figure>` : '';
  // Photographer-creditten håndteres nå i topp-tekstene på hvert bilde
  // (sorte overlays oppe i bildet) — ingen separat credit-boks under.
  const photoCreditHtml = '';

  return `<!-- ============================================
