        const captionHtml = (() => {
          if (!sceneCap || !sceneCap.trim()) return '';
          let txt = escapeHtml(sceneCap);
          if (state.abInCaption) {
            txt = txt.replace(/\[A\]/g, `<span class="banl-ab-chip-${id}">A</span>`)
                     .replace(/\[B\]/g, `<span class="banl-ab-chip-${id}">B</span>`);
          }
          return txt;
        })();
        return `
        <div class="banl-slide-${id}" data-slide="${sIdx}">
          <div class="banl-pair-${id}__images">
            <div class="banl-pair-${id}__cell">
              <!-- ▶ TITTEL VENSTRE — overlay på desktop, over bildet på mobil -->
              <div class="banl-pair-${id}__cell-title banl-pair-${id}__cell-title--left">${escapeHtml(title1)}</div>
              <div class="banl-pair-${id}__cell-clip">
                <img src="${escapeHtml(sd.s.left.url)}" alt="" loading="lazy">
                ${marksHtml(sd.leftMarks)}
              </div>${labelsHtml(sd.leftMarks, true)}
            </div>${hasRight ? `
            <div class="banl-pair-${id}__cell">
              <!-- ▶ TITTEL HØYRE — overlay på desktop, over bildet på mobil -->
              <div class="banl-pair-${id}__cell-title banl-pair-${id}__cell-title--right">${escapeHtml(title2)}</div>
              <div class="banl-pair-${id}__cell-clip">
