    </div>${photoCreditHtml}
  </div>
${figClose}
<script>
(function(){
  var root = document.querySelector('.banl-pair-${id}');
  if(!root) return;

  // Beregn pixel-koordinater for hver konnektor-strek basert på faktisk cell-størrelse.
  // Strek slutter presist på rammens kant (ingen overlap).
  function updateConnectors(){
    var slides = root.querySelectorAll('.banl-slide-${id}');
    slides.forEach(function(slide){
      var imgsContainer = slide.querySelector('.banl-pair-${id}__images');
      if (!imgsContainer) return;
      var cells = slide.querySelectorAll('.banl-pair-${id}__cell');
      var svg = slide.querySelector('.banl-conn-${id}');
      if (!svg || cells.length < 2) return;
      var containerRect = imgsContainer.getBoundingClientRect();
      if (containerRect.width === 0) return;
      var c1 = cells[0].getBoundingClientRect();
      var c2 = cells[1].getBoundingClientRect();
      svg.setAttribute('viewBox', '0 0 ' + containerRect.width + ' ' + containerRect.height);
      svg.setAttribute('preserveAspectRatio', 'none');
      var EXTEND = 3;
      svg.querySelectorAll('line').forEach(function(line){
        var ax = parseFloat(line.getAttribute('data-ax')) || 0;
        var ay = parseFloat(line.getAttribute('data-ay')) || 0;
        var bx = parseFloat(line.getAttribute('data-bx')) || 0;
        var by = parseFloat(line.getAttribute('data-by')) || 0;
        var x1 = (c1.left + ax * c1.width / 100) - containerRect.left;
        var y1 = (c1.top + ay * c1.height / 100) - containerRect.top;
        var x2 = (c2.left + bx * c2.width / 100) - containerRect.left;
        var y2 = (c2.top + by * c2.height / 100) - containerRect.top;
        // Forleng langs vektoren så streken treffer rammen presist uansett vinkel
        var dx = x2 - x1, dy = y2 - y1;
        var len = Math.sqrt(dx*dx + dy*dy);
        if (len > 0) {
          var ux = dx / len, uy = dy / len;
          x1 -= ux * EXTEND;
          y1 -= uy * EXTEND;
          x2 += ux * EXTEND;
          y2 += uy * EXTEND;
        }
        line.setAttribute('x1', x1);
        line.setAttribute('y1', y1);
        line.setAttribute('x2', x2);
        line.setAttribute('y2', y2);
        line.setAttribute('stroke-linecap', 'butt');
      });
    });
  }

  ${total > 1 ? `
  // Slideshow med transform-based animasjon
  var track = root.querySelector('.banl-slides-${id}__track');
  var slides = root.querySelectorAll('.banl-slide-${id}');
  var dots = root.querySelectorAll('.banl-pair-${id}__dots span');
  var prev = root.querySelector('[data-act="prev"]');
  var next = root.querySelector('[data-act="next"]');
  var idx = 0;
  function show(i){
    idx = (i + slides.length) % slides.length;
    if (track) track.style.transform = 'translateX(-' + (idx * 100) + '%)';
    dots.forEach(function(d, n){ d.classList.toggle('is-active', n === idx); });
    if(prev) prev.disabled = idx === 0;
    if(next) next.disabled = idx === slides.length - 1;
    requestAnimationFrame(updateConnectors);
  }
  if(prev) prev.addEventListener('click', function(){ show(idx - 1); });
  if(next) next.addEventListener('click', function(){ show(idx + 1); });
  dots.forEach(function(d, n){ d.addEventListener('click', function(){ show(n); }); });
  show(0);
  // Initial hint: vis at det er mer ved å peek på neste slide kort.
  // Trigges når embeden scrolles inn i viewport (ikke ved page load).
  // Kjøres bare én gang per sidevisning.
  if (slides.length > 1) {
    var wrap = root.querySelector('.banl-pair-${id}__wrap');
    if (wrap) {
      var hintShown = false;
      var triggerHint = function(){
        if (hintShown) return;
        hintShown = true;
        wrap.classList.add('is-hinting');
        setTimeout(function(){ wrap.classList.remove('is-hinting'); }, 2200);
      };
      if ('IntersectionObserver' in window) {
        var io = new IntersectionObserver(function(entries){
          entries.forEach(function(en){
            // Vent til minst 35% av boksen er synlig — da er det tydelig at leseren har scrollet til den
            if (en.isIntersecting && en.intersectionRatio >= 0.35) {
              triggerHint();
              io.disconnect();
            }
          });
        }, { threshold: [0.35, 0.6] });
        io.observe(wrap);
        // Fallback: hvis embeden allerede er i viewport ved load, trigger kort etter
        var rect = wrap.getBoundingClientRect();
        var vh = window.innerHeight || document.documentElement.clientHeight;
        if (rect.top < vh * 0.65 && rect.bottom > vh * 0.2) {
          setTimeout(triggerHint, 600);
        }
      } else {
        // Eldre nettlesere: kjør hint kort etter load
        setTimeout(triggerHint, 800);
      }
    }
  }
  // Touch swipe
  var startX = 0;
  root.addEventListener('touchstart', function(e){ startX = e.touches[0].clientX; }, {passive: true});
  root.addEventListener('touchend', function(e){
    var dx = e.changedTouches[0].clientX - startX;
    if(Math.abs(dx) > 50) show(idx + (dx < 0 ? 1 : -1));
  });
  ` : ''}

  // Tegn konnektorer ved load + resize
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', updateConnectors);
  }
  // Vent på at bilder lastes så aspect-ratio er ferdig beregnet
  var imgs = root.querySelectorAll('img');
  imgs.forEach(function(img){
    if (img.complete) updateConnectors();
    else img.addEventListener('load', updateConnectors);
  });
  requestAnimationFrame(updateConnectors);
  window.addEventListener('resize', updateConnectors);
})();
</script>
`;
}

