          const g = state.groups.find(gg => gg.id === mk.groupId);
          const c = g ? g.color : '#fff';
          return `
        <div class="banl-mark-${id}" style="left:${mk.x.toFixed(2)}%;top:${mk.y.toFixed(2)}%;width:${mk.w.toFixed(2)}%;height:${mk.h.toFixed(2)}%;--c:${c};"></div>`;
