<script>
(function(){
  var IMAGES = ${imageDataJson};
  var GROUPS = ${groupsJson};
  var lb = document.getElementById('lb-${id}');
  if(!lb) return;
  var wrap = document.getElementById('lb-${id}-wrap');
  var header = document.getElementById('lb-${id}-header');
  var current = { groupId: null, indices: [], pos: 0 };
  function findGroup(gid){ for(var i=0;i<GROUPS.length;i++) if(GROUPS[i].id===gid) return GROUPS[i]; return null; }
  function render() {
    var g = findGroup(current.groupId);
    if(!g || !current.indices.length) return;
    var idx = current.indices[current.pos];
    var img = IMAGES[idx];
    var marksHtml = '';
    var filteredMarks = img.marks.filter(function(m){return m.g === current.groupId;});
    for (var i=0;i<filteredMarks.length;i++){
      var m = filteredMarks[i];
      marksHtml += '<div style="position:absolute;border:5px solid '+g.color+';box-sizing:border-box;border-radius:2px;left:'+m.x+'%;top:'+m.y+'%;width:'+m.w+'%;height:'+m.h+'%;"></div>';
    }
    wrap.innerHTML = '<img src="'+img.url+'" alt="">'+marksHtml;
    var labelPart = img.label ? ' · Bilde '+img.label : '';
    header.innerHTML = '<span style="display:inline-block;width:14px;height:14px;background:'+g.color+';border-radius:3px;"></span> '+g.label+' — '+(current.pos+1)+' av '+current.indices.length+labelPart;
  }
  function openGroup(gid){
    var g = findGroup(gid);
    if(!g) return;
    var indices = [];
    for(var i=0;i<IMAGES.length;i++){
      if(IMAGES[i].marks.some(function(m){return m.g===gid;})) indices.push(i);
    }
    if(!indices.length) return;
    current.groupId = gid;
    current.indices = indices;
    current.pos = 0;
    render();
    lb.classList.add('is-open');
    document.body.style.overflow = 'hidden';
  }
  function close(){
    lb.classList.remove('is-open');
    document.body.style.overflow = '';
  }
  function nav(dir){
    if(!current.indices.length) return;
    current.pos = (current.pos + dir + current.indices.length) % current.indices.length;
    render();
  }
  document.querySelectorAll('.banl-legend__item').forEach(function(btn){
    btn.addEventListener('click', function(){ openGroup(btn.dataset.grp); });
  });
  lb.querySelector('.banl-lb-${id}__close').addEventListener('click', close);
  lb.querySelector('.banl-lb-${id}__nav--prev').addEventListener('click', function(e){ e.stopPropagation(); nav(-1); });
  lb.querySelector('.banl-lb-${id}__nav--next').addEventListener('click', function(e){ e.stopPropagation(); nav(1); });
  lb.addEventListener('click', function(e){ if(e.target === lb) close(); });
  document.addEventListener('keydown', function(e){
    if(!lb.classList.contains('is-open')) return;
    if(e.key === 'Escape') close();
    else if(e.key === 'ArrowLeft') nav(-1);
    else if(e.key === 'ArrowRight') nav(1);
  });
  var touchStartX = 0;
  lb.addEventListener('touchstart', function(e){ touchStartX = e.touches[0].clientX; }, {passive:true});
  lb.addEventListener('touchend', function(e){
    var dx = e.changedTouches[0].clientX - touchStartX;
    if(Math.abs(dx) > 50) nav(dx < 0 ? 1 : -1);
  });
})();
</script>
`;
}

