    pairMode: state.pairMode,
    pairFormat: state.pairFormat,
    pairTitles: state.pairTitles,
    sceneCaptions: state.sceneCaptions,
    topHeading: state.topHeading,
    headingStyle: state.headingStyle,
    dimOutside: state.dimOutside,
    abInCaption: state.abInCaption,
    captionText: els.captionText.value,
    photographer: els.photographer.value,
  };
}
async function applyState(saved) {
  if (!saved) return;
  isRestoring = true;
  try {
    els.captionText.value = saved.captionText || '';
    els.photographer.value = saved.photographer || '';
    if (Array.isArray(saved.imageUrls)) {
      state.imageUrls = saved.imageUrls.length ? saved.imageUrls : [''];
      // Sett labels: bruk lagrede, eller fyll med default A/B/C..
      state.imageLabels = (Array.isArray(saved.imageLabels) ? saved.imageLabels : [])
        .concat(state.imageUrls.slice((saved.imageLabels || []).length).map((_, i) =>
          defaultLabel((saved.imageLabels || []).length + i)));
      // Trim hvis for langt
      state.imageLabels.length = state.imageUrls.length;
      renderImageInputs();
    }
    if (Array.isArray(saved.groups) && saved.groups.length) state.groups = saved.groups;
    if (Array.isArray(saved.marks)) state.marks = saved.marks;
    if (saved.selectedGroupId) state.selectedGroupId = saved.selectedGroupId;
    if (Array.isArray(saved.sourceVideos)) state.sourceVideos = saved.sourceVideos;
    if (saved.pairMode) state.pairMode = saved.pairMode;
    if (saved.pairFormat) {
      state.pairFormat = saved.pairFormat;
      if (els.pairFormatSelect) els.pairFormatSelect.value = saved.pairFormat;
    }
    if (Array.isArray(saved.pairTitles)) {
      state.pairTitles = saved.pairTitles;
      if (els.pairTitle1) els.pairTitle1.value = saved.pairTitles[0] || 'Bilde 1';
      if (els.pairTitle2) els.pairTitle2.value = saved.pairTitles[1] || 'Bilde 2';
    }
    if (Array.isArray(saved.sceneCaptions)) state.sceneCaptions = saved.sceneCaptions;
    if (typeof saved.topHeading === 'string') {
      state.topHeading = saved.topHeading;
      if (els.topHeading) els.topHeading.value = saved.topHeading;
    }
    if (typeof saved.headingStyle === 'string') {
      state.headingStyle = saved.headingStyle;
      if (els.headingStyle) els.headingStyle.value = saved.headingStyle;
    }
    if (typeof saved.dimOutside === 'boolean') {
      state.dimOutside = saved.dimOutside;
      if (els.dimOutside) els.dimOutside.checked = saved.dimOutside;
    }
    if (typeof saved.abInCaption === 'boolean') {
      state.abInCaption = saved.abInCaption;
      if (els.abInCaption) els.abInCaption.checked = saved.abInCaption;
    }
    renderVideoInputs();
    if (saved.imageUrls && saved.imageUrls.filter(u => u && u.trim()).length >= 2) {
      await loadAllImages();
    }
  } finally {
    isRestoring = false;
  }
}

let saveTimer = null;
function scheduleSaveState() {
  if (isRestoring) return;
  clearTimeout(saveTimer);
  saveTimer = setTimeout(() => {
    window.faktisk.stateSave(PLUGIN_ID, serializeState()).catch(console.error);
  }, 400);
}
['input', 'change'].forEach(ev => {
  els.captionText.addEventListener(ev, () => {
    if (isPair()) {
      // Lagre teksten på aktiv scene i slideshow
      setSceneCaption(state.activeSceneIdx, els.captionText.value);
      renderGrid();
    }
    scheduleSaveState();
  });
  els.photographer.addEventListener(ev, scheduleSaveState);
});

function syncCaptionFieldToScene() {
  if (!isPair()) {
    if (els.captionLabel) els.captionLabel.textContent = 'Bildetekst (valgfri)';
    els.captionText.placeholder = 'Forklar sammenhengen kort…';
    return;
  }
  const total = sceneCount();
  const cap = getSceneCaption(state.activeSceneIdx) || '';
  if (els.captionText.value !== cap) {
    isRestoring = true;
    els.captionText.value = cap;
    isRestoring = false;
  }
  // Vis hvilken scene captionet gjelder for
  if (els.captionLabel) {
    els.captionLabel.textContent = total > 1
      ? `Bildetekst for scene ${state.activeSceneIdx + 1} av ${total}`
      : 'Bildetekst (valgfri)';
  }
  els.captionText.placeholder = total > 1
    ? `Tekst for dette bildeparet (bytter når du blar til neste)…`
    : 'Forklar sammenhengen kort…';
}

async function refreshProjectList() {
  try {
    const res = await window.faktisk.projectList(PLUGIN_ID);
    if (!res.ok) return;
    const sel = els.projectSelect;
    while (sel.options.length > 1) sel.remove(1);
    res.projects.forEach(p => {
      const opt = document.createElement('option');
      opt.value = p.fileId;
      opt.textContent = p.name;
      sel.appendChild(opt);
    });
  } catch (e) { console.error(e); }
}
els.saveProject.addEventListener('click', async () => {
  const defaultName = (els.captionText.value || '').slice(0, 40).trim()
    || `Analyse ${new Date().toLocaleDateString('no')}`;
  const name = await window.faktiskDialog.prompt('Lagre prosjekt som:', defaultName);
  if (!name || !name.trim()) return;
  const res = await window.faktisk.projectSave(PLUGIN_ID, name.trim(), serializeState());
  if (res.ok) {
    setStatus('Lagret: «' + res.name + '».');
    await refreshProjectList();
  }
});
els.projectSelect.addEventListener('change', async () => {
  const fileId = els.projectSelect.value;
  if (!fileId) return;
  const res = await window.faktisk.projectLoad(PLUGIN_ID, fileId);
  if (res.ok && res.state) {
    setStatus('Åpner «' + res.name + '»…');
    await applyState(res.state);
  }
});

(async function init() {
  // Sett default-label for første rad om den mangler
  if (!state.imageLabels[0]) state.imageLabels[0] = defaultLabel(0);
  renderImageInputs();
  renderVideoInputs();
  updateExportButtons();
  await refreshProjectList();
  try {
    const res = await window.faktisk.stateLoad(PLUGIN_ID);
    if (res.ok && res.state) await applyState(res.state);
  } catch (e) {}
})();

