// Faktisk Studio · delt dialog-modul
// window.prompt og window.confirm er blokkert i Electron. Vi bygger
// en custom modal som matcher Faktisk-designet og returnerer Promise.

(function () {
  function ensureContainer() {
    let host = document.getElementById('faktisk-dialog-host');
    if (host) return host;
    host = document.createElement('div');
    host.id = 'faktisk-dialog-host';
    document.body.appendChild(host);
    const style = document.createElement('style');
    style.textContent = `
      #faktisk-dialog-host {
        position: fixed; inset: 0; display: none;
        align-items: center; justify-content: center;
        background: rgba(0,0,0,0.45);
        z-index: 99999;
        font-family: var(--font-regular), "Helvetica Neue", sans-serif;
      }
      #faktisk-dialog-host.open { display: flex; }
      .fd-card {
        background: #fff;
        color: #212121;
        border-radius: 14px;
        padding: 24px 28px;
        width: 420px;
        max-width: calc(100vw - 40px);
        box-shadow: 0 24px 60px rgba(0,0,0,0.4);
        display: flex;
        flex-direction: column;
        gap: 14px;
      }
      .fd-message {
        font-size: 15px;
        line-height: 1.4;
        margin: 0;
        color: #212121;
        font-weight: 500;
      }
      .fd-input {
        background: #f0f0f0;
        border: 0;
        outline: 0;
        border-radius: 7px;
        padding: 10px 12px;
        font-size: 14px;
        font-family: inherit;
        color: #212121;
        font-weight: 500;
      }
      .fd-input:focus { outline: 2px solid #0050FC; }
      .fd-row {
        display: flex;
        gap: 10px;
        justify-content: flex-end;
        margin-top: 4px;
      }
      .fd-btn {
        padding: 10px 20px;
        font-size: 14px;
        font-weight: bold;
        border: 0;
        border-radius: 9px;
        cursor: pointer;
        font-family: inherit;
      }
      .fd-btn-primary { background: #0050FC; color: #fff; }
      .fd-btn-primary:hover { background: #0040D9; }
      .fd-btn-cancel { background: #e0e0e0; color: #212121; }
      .fd-btn-cancel:hover { background: #d0d0d0; }
      .fd-btn-danger { background: #d04040; color: #fff; }
      .fd-btn-danger:hover { background: #e85050; }
      .fd-progress-label {
        font-size: 13px;
        color: #555;
        margin: 0;
      }
      .fd-progress {
        height: 8px;
        background: #e0e0e0;
        border-radius: 4px;
        overflow: hidden;
      }
      .fd-progress__bar {
        height: 100%;
        background: #0050FC;
        transition: width 0.2s;
      }
      .project-card {
        background: #0050FC;
        color: #fff;
        border-radius: 9px;
        padding: 12px 16px;
        cursor: pointer;
        display: flex;
        flex-direction: column;
        gap: 4px;
        position: relative;
        transition: background 0.15s;
      }
      .project-card:hover { background: #0040D9; }
      .project-card__name { font-weight: bold; font-size: 14px; }
      .project-card__meta { font-size: 11px; opacity: 0.85; }
      .project-card__delete {
        position: absolute; top: 6px; right: 8px;
        background: rgba(255,255,255,0.18); color: #fff;
        width: 22px; height: 22px; border-radius: 4px;
        display: none; align-items: center; justify-content: center;
        font-size: 14px; cursor: pointer; border: 0;
      }
      .project-card:hover .project-card__delete { display: flex; }
      .project-card__delete:hover { background: rgba(255,80,80,0.85); }
    `;
    document.head.appendChild(style);
    return host;
  }

  function open(html, onMount) {
    const host = ensureContainer();
    host.innerHTML = `<div class="fd-card">${html}</div>`;
    host.classList.add('open');
    if (onMount) onMount(host);
    return () => { host.classList.remove('open'); host.innerHTML = ''; };
  }

  function prompt(message, defaultValue) {
    return new Promise(resolve => {
      const close = open(`
        <p class="fd-message"></p>
        <input class="fd-input" type="text">
        <div class="fd-row">
          <button class="fd-btn fd-btn-cancel" data-act="cancel">Avbryt</button>
          <button class="fd-btn fd-btn-primary" data-act="ok">OK</button>
        </div>
      `, host => {
        host.querySelector('.fd-message').textContent = message || '';
        const input = host.querySelector('.fd-input');
        input.value = defaultValue || '';
        setTimeout(() => { input.focus(); input.select(); }, 30);
        const cleanup = result => { close(); resolve(result); };
        host.querySelector('[data-act="ok"]').onclick = () => cleanup(input.value);
        host.querySelector('[data-act="cancel"]').onclick = () => cleanup(null);
        input.onkeydown = e => {
          if (e.key === 'Enter') cleanup(input.value);
          if (e.key === 'Escape') cleanup(null);
        };
      });
    });
  }

  function confirm(message, danger) {
    return new Promise(resolve => {
      const okClass = danger ? 'fd-btn-danger' : 'fd-btn-primary';
      const close = open(`
        <p class="fd-message"></p>
        <div class="fd-row">
          <button class="fd-btn fd-btn-cancel" data-act="cancel">Avbryt</button>
          <button class="fd-btn ${okClass}" data-act="ok">${danger ? 'Slett' : 'OK'}</button>
        </div>
      `, host => {
        host.querySelector('.fd-message').textContent = message || '';
        const cleanup = result => { close(); resolve(result); };
        host.querySelector('[data-act="ok"]').onclick = () => cleanup(true);
        host.querySelector('[data-act="cancel"]').onclick = () => cleanup(false);
        document.onkeydown = e => {
          if (e.key === 'Escape') { document.onkeydown = null; cleanup(false); }
        };
      });
    });
  }

  function alert(message) {
    return new Promise(resolve => {
      const close = open(`
        <p class="fd-message"></p>
        <div class="fd-row">
          <button class="fd-btn fd-btn-primary" data-act="ok">OK</button>
        </div>
      `, host => {
        host.querySelector('.fd-message').textContent = message || '';
        const cleanup = () => { close(); resolve(); };
        host.querySelector('[data-act="ok"]').onclick = cleanup;
      });
    });
  }

  window.faktiskDialog = { prompt, confirm, alert };
})();

shared/style.css:
/* ============================================
   FAKTISK STUDIO — designsystem
   Henter farger og radii fra Figma-skissen
   ============================================ */

:root {
  --faktisk-blue: #0050FC;
  --faktisk-blue-hover: #0040D9;
  --bg-page: #9D9D9D;
  --bg-topbar: #707070;
  --bg-placeholder: #7B7B7B;
  --bg-letterbox: #878787;
  --bg-input: #D9D9D9;
  --text-on-blue: #FFFFFF;
  --text-topbar-title: #414141;
  --text-placeholder: #8B8B8B;
  --text-input: #313131;

  --radius-container: 30px;
  --radius-card: 15px;
  --radius-button: 11px;
  --radius-button-sm: 7px;
  --radius-input: 6px;

  --font-bold: "Haas Grot Text 75 Bold", "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-regular: "Haas Grot Text 55 Roman", "Helvetica Neue", Helvetica, Arial, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  height: 100%;
  background: var(--bg-page);
  font-family: var(--font-regular);
  color: #fff;
  user-select: none;
  -webkit-user-select: none;
  overflow: hidden;
}

button {
  font-family: inherit;
  border: 0;
  cursor: pointer;
  background: none;
  color: inherit;
  padding: 0;
}

/* ============================================
   Hovedcontainer
   ============================================ */
.studio {
  background: var(--bg-page);
  border-radius: var(--radius-container);
  padding: 41px 26px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  height: 100%;
  overflow: hidden;
}

/* ============================================
   Topp-bar
   ============================================ */
.topbar {
  background: var(--bg-topbar);
  border-radius: var(--radius-card);
  padding: 22px 27px;
  display: flex;
  align-items: center;
  gap: 24px;
  flex-shrink: 0;
}

/* Diskret versjonsindikator ved siden av logo */
.topbar__version {
  font-family: var(--font-bold);
  font-size: 11px;
  font-weight: bold;
  color: #fff;
  opacity: 0.5;
  letter-spacing: 0.04em;
  white-space: nowrap;
  margin-left: -12px;   /* trekk tett inn mot logo */
}

/* Labrador-logo i toppen — hvit via CSS-mask */
.topbar__title {
  flex: 1;
  height: 28px;
  margin: 0;
  background: #fff;
  -webkit-mask: url('labrador-logo.svg') no-repeat center / contain;
  mask: url('labrador-logo.svg') no-repeat center / contain;
}

.topbar__actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.btn-primary {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 15px;
  height: 52px;
  padding: 0 22px;
  border-radius: var(--radius-button);
  min-width: 129px;
  transition: background 0.15s;
}
.btn-primary:hover { background: var(--faktisk-blue-hover); }

.btn-icon {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-size: 30px;
  width: 52px;
  height: 52px;
  border-radius: var(--radius-button);
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  transition: background 0.15s;
}
.btn-icon:hover { background: var(--faktisk-blue-hover); }

/* Sekundærknapp i topp-bar (Mine prosjekter) */
.btn-secondary-tb {
  background: rgba(0,0,0,0.18);
  color: #fff;
  font-family: var(--font-bold);
  font-weight: bold;
  font-size: 15px;
  height: 52px;
  padding: 0 22px;
  border-radius: var(--radius-button);
  transition: background 0.15s;
}
.btn-secondary-tb:hover { background: rgba(0,0,0,0.28); }

.projects-modal {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 10px;
  max-height: 50vh;
  overflow: auto;
  padding: 4px;
}

.projects-modal__empty {
  text-align: center;
  padding: 30px;
  color: #666;
  font-size: 14px;
}

/* Plugin-marked */
.market-body {
  max-height: 60vh;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 4px;
}
.market-empty {
  text-align: center;
  padding: 40px 20px;
  color: #666;
  font-size: 14px;
}
.market-row {
  display: flex;
  gap: 14px;
  align-items: center;
  padding: 14px 16px;
  background: #f5f5f5;
  border-radius: 10px;
}
.market-row__info { flex: 1; min-width: 0; }
.market-row__name {
  font-family: var(--font-bold);
  font-size: 15px;
  font-weight: bold;
  color: #212121;
}
.market-row__desc {
  font-size: 13px;
  color: #444;
  margin-top: 2px;
  line-height: 1.35;
}
.market-row__meta {
  font-size: 12px;
  color: #666;
  margin-top: 4px;
}
.market-row__changelog {
  font-size: 12px;
  color: #555;
  margin-top: 6px;
  padding-top: 6px;
  border-top: 1px solid #e0e0e0;
  font-style: italic;
}
.market-row__action { flex-shrink: 0; }

/* ============================================
   Plugin-grid (Malside)
   ============================================ */
.malside {
  flex: 1;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 22px;
  overflow: auto;
  padding: 4px;
}

.malside__column {
  display: flex;
  flex-direction: column;
  gap: 22px;
}

/* Plugin-kort — installert (blå). Fast høyde så installerte og placeholders får samme størrelse. */
.plugin-card {
  background: var(--faktisk-blue);
  border-radius: var(--radius-card);
  padding: 0 35px;
  display: flex;
  align-items: center;
  cursor: pointer;
  height: 90px;
  transition: background 0.15s, transform 0.1s;
}
.plugin-card:hover { background: var(--faktisk-blue-hover); }
.plugin-card:active { transform: scale(0.98); }

.plugin-card__title {
  font-family: var(--font-bold);
  font-size: 22px;
  font-weight: bold;
  color: #fff;
  margin: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.plugin-card--placeholder {
  background: var(--bg-placeholder);
  display: flex;
  justify-content: space-between;
  cursor: default;
}
.plugin-card--placeholder:hover { background: var(--bg-placeholder); }
.plugin-card--placeholder:active { transform: none; }

.plugin-card--placeholder .plugin-card__title {
  color: var(--text-placeholder);
}

.plugin-card__add {
  background: var(--faktisk-blue);
  color: #fff;
  font-family: var(--font-bold);
  font-size: 30px;
  width: 36px;
  height: 36px;
  border-radius: var(--radius-button-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  cursor: pointer;
  flex-shrink: 0;
  transition: background 0.15s;
}
.plugin-card__add:hover { background: var(--faktisk-blue-hover); }

/* ============================================
   Faktisk Studio-logo (CSS mask)
   ============================================ */
.faktisk-logo {
  width: 178px;
  height: 26px;
  background: #fff;
  -webkit-mask: url('logo.svg') no-repeat center / contain;
  mask: url('logo.svg') no-repeat center / contain;
  flex-shrink: 0;
}

